import {
    addAwardAssignment,
    listAwardAssignments,
    listAwardEligibleTeams,
    listAwards,
    removeAwardAssignment,
    setAwardAssignment,
    submitTeamAwards,
    unsubmitTeamAwards,
    useAwardPresentationContext
} from "../api";
import {useMutation, useQuery, useQueryClient} from "@tanstack/react-query";
import {Button, Card, Col, Form, ListGroup, OverlayTrigger, Row, Tooltip} from "react-bootstrap";
import {t} from "../../i18n";
import {useEffect, useState} from "react";
import {Award, AwardAssignment, AwardId} from "../../javaTypes";
import {getAwardLabel} from "../utils";
import Select from "react-select";
import {confirmDialog} from "first-common/dialogs";

enum AwardWarningLevel {
    INFO,
    WARNING,
    ERROR
}

interface AwardWarning {
    type: AwardWarningLevel;
    series: number;
    message: string;
    contextMessage: string;
}

function AwardAssignmentEditor({award, assignment, assignments, warnings}: { award: Award, assignment: AwardAssignment, assignments: AwardAssignment[], warnings: AwardWarning[] }) {
    const [name, setName] = useState(assignment.name)
    const [team, setTeam] = useState<number | undefined>(assignment.team?.number)
    const [comment, setComment] = useState(assignment.comment)
    const queryClient = useQueryClient();
    useEffect(() => {
        setName(assignment.name)
        setTeam(assignment.team?.number)
        setComment(assignment.comment)
    }, [award.awardId, assignment.series]);

    const saveAwardMutation = useMutation({
        mutationFn: async (newValues: { name?: string, team?: number, comment?: string }) => {
            await setAwardAssignment(window.eventCode, award.awardId, assignment.series, { name, team: team, comment, ...newValues })
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({queryKey: ["awardAssignments", window.eventCode]});
        }
    })

    const teamData = useQuery({
        queryKey: ["awardTeams", window.eventCode],
        queryFn: () => listAwardEligibleTeams(window.eventCode)
    })

    if(teamData.isLoading || teamData.isPending) {
        return <div>{t`Loading...`}</div>
    }
    if(teamData.isError) {
        return <div>{t`Error loading teams`}</div>
    }

    const options = teamData.data.map(t => ({
        value: t.team.number,
        label: `${t.team.displayNumber} - ${t.team.name}`,
        raw: t
    }));

    const selectedTeam = options.find(t => t.value == team) || null;
    const awardLabel = getAwardLabel(award, assignment.series, assignments.length);
    return <>
        <b>{awardLabel}</b>
        <Row>
            {award.isTeamAward ? null : <Form.Group className="col-5" controlId={`${award.awardId}-${assignment.series}-name`}>
                <Form.Label>{t`Name`}</Form.Label>
                <Form.Control value={name || ''} onChange={(e) => { setName(e.target.value); saveAwardMutation.mutate({ name: e.target.value })}}/>
            </Form.Group>}
            <Form.Group className={award.isTeamAward ? "col" : "col-7"} controlId={`${award.awardId}-${assignment.series}-team`}>
                <Form.Label>{award.isTeamAward ? t`Team` : t`Team (optional)`}</Form.Label>
                <Select options={options} value={selectedTeam} className={warnings.length > 0 ? "is-invalid" : ""}
                        isClearable aria-label={`${awardLabel} Team`}
                        onChange={e => {
                            setTeam(e?.value);
                            saveAwardMutation.mutate({ team: e?.value })
                        }} />
                <Form.Control.Feedback type="invalid" >
                    <i className={"fa fa-exclamation-triangle"}/> {warnings.map(w => w.contextMessage).join(", ")}
                </Form.Control.Feedback>
            </Form.Group>
        </Row>
        {assignment.series == 1 || award.awardTypeId == AwardId.INSPIRE_ID || award.awardTypeId == AwardId.DEANSLIST_ID ? <Form.Group className={"mt-2"} controlId={`${award.awardId}-${assignment.series}-team`}>
            <Form.Label>{t`Judges' Comments`}</Form.Label>
            <Form.Control as={"textarea"} rows={3} onChange={(e) => { setComment(e.target.value); saveAwardMutation.mutate({ comment: e.target.value }) }} value={comment || ''}></Form.Control>
        </Form.Group> : null}
    </>;
}

function AwardAssignmentsEditor({award, awardAssignments, warnings}: { award: Award, awardAssignments: AwardAssignment[], warnings: AwardWarning[] }) {
    const hasWinner = award.isTeamAward && awardAssignments?.[0]?.team || awardAssignments?.[0]?.name

    const queryClient = useQueryClient();

    const addAssignmentMutation = useMutation({
        mutationFn: async () => {
            await addAwardAssignment(window.eventCode, award.awardId)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({queryKey: ["awardAssignments", window.eventCode]});
        }
    })

    const removeAssignmentMutation = useMutation({
        mutationFn: async () => {
            await removeAwardAssignment(window.eventCode, award.awardId)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({queryKey: ["awardAssignments", window.eventCode]});
        }
    })

    return <Card>
        <Card.Body>
            <Card.Title dangerouslySetInnerHTML={{__html: award.name}}></Card.Title>
            <Card.Text dangerouslySetInnerHTML={{__html: award.script}}></Card.Text>
            <div className={"mb-3"}><b>Status</b> {hasWinner ? t`Already given` : (warnings.some(w => w.type == AwardWarningLevel.INFO) ? t`Must be given` : t`Optional`)}</div>
            {awardAssignments.map(aa => {
                return <div className={"mb-3"} key={aa.series}>
                    <AwardAssignmentEditor award={award} assignment={aa} assignments={awardAssignments} warnings={warnings.filter(w => w.series == aa.series)} />
                </div>
            })}
            {award.editable || award.awardTypeId == AwardId.DEANSLIST_ID ? <div className={"mb-3"}>
                <Button variant={"secondary"} className={"mr-2"} onClick={() => {
                    addAssignmentMutation.mutate();
                }}>{t`Add slot`}</Button>
                <Button variant={"secondary"} onClick={async () => {
                    removeAssignmentMutation.mutate();
                }}>{t`Remove slot`}</Button>
            </div> : null}
        </Card.Body>
    </Card>;
}

function isOfficialTeamAward(award: Award) {
    // We want to exclude e.g. Compass, Winning Alliance, and any custom awards because those are not covered by
    // A215 (per staff interpretation) and as non-points-generating awards it doesn't really matter if there are dupes
    return award.isTeamAward && award.allowManualEntry && award.awardTypeId != AwardId.CUSTOM_ID;
}

function isTAAward(a: Award) {
    return a.awardTypeId == AwardId.CONNECT_ID || a.awardTypeId == AwardId.REACH_ID || a.awardTypeId == AwardId.SUSTAIN_ID;
}

function isMCIAward(a: Award) {
    return a.awardTypeId == AwardId.INNOVATE_ID || a.awardTypeId == AwardId.DESIGN_ID || a.awardTypeId == AwardId.CONTROL_ID;
}

export default function GiveAwards() {
    const queryClient = useQueryClient()
    const awardData = useQuery({
        queryKey: ["awards", window.eventCode],
        queryFn: () => listAwards(window.eventCode)
    })
    const awardAssignmentData = useQuery({
        queryKey: ["awardAssignments", window.eventCode],
        queryFn: () => listAwardAssignments(window.eventCode)
    })
    const teamData = useQuery({
        queryKey: ["awardTeams", window.eventCode],
        queryFn: () => listAwardEligibleTeams(window.eventCode)
    })
    const awardPresentationContext = useAwardPresentationContext(window.eventCode);

    const submitAwardsMutation = useMutation({
        mutationFn: async ({awards, awardWarnings} : { awards: Award[], awardWarnings: Record<string, AwardWarning[]> }) => {
            if(Object.values(awardWarnings).some(a => a.length > 0)) {
                if(!await confirmDialog({
                    label: t`Confirm Award Submission`,
                    text: t`There are warnings with the current award assignments. Are you sure you want to submit?` +
                        `<ul>${awards.map((a) => awardWarnings[a.awardId]?.length > 0 ? `<li><b>${a.name}:</b><br/>${awardWarnings[a.awardId].map(w => w.message).join("<br/>")}</li>` : '').join("")}</ul>`,
                    buttonText: t`Submit Anyway`
                })) {
                    return;
                }
            }
            await submitTeamAwards(window.eventCode)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({
                queryKey: ["awardPresentationContext", window.eventCode]
            })
        }
    })
    const unsubmitAwardsMutation = useMutation({
        mutationFn: async () => {
            await unsubmitTeamAwards(window.eventCode)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({
                queryKey: ["awardPresentationContext", window.eventCode]
            })
        }
    })
    const [selectedAward, setSelectedAward] = useState<string | null>(null)

    if(awardData.isLoading || awardAssignmentData.isLoading || awardData.isPending || awardAssignmentData.isPending) {
        return <div>{t`Loading...`}</div>
    }
    if(awardData.isError || awardAssignmentData.isError) {
        return <div>{t`Error`}</div>
    }

    const editableAwards = awardData.data.filter(a => a.allowManualEntry).toSorted((a, b) => a.order - b.order);

    const awardWarnings: Record<string, AwardWarning[]> = Object.fromEntries(editableAwards.map(a => {
        const requiredRange = Array.from({ length: a.requiredCount },(v,k) => k+1)
        const ret: AwardWarning[] = []
        if(isOfficialTeamAward(a)) {
            const possibleDuplicates = awardData.data.filter(a2 => isOfficialTeamAward(a2))
            awardAssignmentData.data[a.awardId].forEach(myAssignment => {
                if(!myAssignment.team) return
                const otherAssignments =  possibleDuplicates.flatMap(a => (awardAssignmentData.data[a.awardId] ?? []).map(aa => ({ ...aa, award: a })))
                    .filter((assignment) => !(assignment.award.awardId == a.awardId && assignment.series == myAssignment.series))
                const duplicateAssignments = otherAssignments.filter(aa2 => aa2.team?.number == myAssignment.team?.number)
                duplicateAssignments.forEach(assignment => {
                    const myLabel = getAwardLabel(a, myAssignment.series, awardAssignmentData.data[a.awardId].length);
                    const theirLabel = getAwardLabel(assignment.award, assignment.series, awardAssignmentData.data[assignment.award.awardId].length)
                    ret.push({
                        type: AwardWarningLevel.WARNING,
                        series: myAssignment.series,
                        message: t`Duplicate ${myLabel} with ${assignment.award.name} ${theirLabel}`,
                        contextMessage: t`Duplicate with ${assignment.award.name} ${theirLabel}`,
                    })
                })
            })

            // These are all team awards, so we can just check for team to know if it has been assigned
            const missingRequiredAssignments = requiredRange.filter(series => awardAssignmentData.data[a.awardId].filter(aa => aa.series == series && aa.team).length == 0)
            missingRequiredAssignments.forEach(series => {
                const myLabel = getAwardLabel(a, series, awardAssignmentData.data[a.awardId].length);
                ret.push({
                    type: AwardWarningLevel.INFO,
                    series,
                    message: t`Missing required ${myLabel}`,
                    contextMessage: t`Required`
                })
            })

            const winner = awardAssignmentData.data[a.awardId]?.find(aa => aa.series == 1)
            const isInspireIneligible = a.awardTypeId == AwardId.INSPIRE_ID && winner?.team && !teamData.data?.find(t => t.team.number == winner.team?.number)?.inspireEligible;
            if(isInspireIneligible) {
                ret.push({
                    type: AwardWarningLevel.ERROR,
                    series: 1,
                    message: t`Inspire award winner ineligible!`,
                    contextMessage: t`Ineligible for Inspire!`
                })
            }
        }

        return [a.awardId, ret];
    }))

    // Check TA and MCI for tiny events
    // At tiny events we make these normally required awards all have a required count of 0 so that the end of event
    // submission doesn't flag them as empty, but we still actually need one of the three
    const taAwards = editableAwards.filter(a => isTAAward(a));
    const mciAwards = editableAwards.filter(a => isMCIAward(a));
    if(taAwards.every(a => a.requiredCount == 0)) {
        const taAwardsWithWinners = taAwards.filter(a => awardAssignmentData.data[a.awardId].some(a => a.series == 1 && a.team));
        if (taAwardsWithWinners.length == 0) {
            taAwards.forEach(a => {
                awardWarnings[a.awardId].push({
                    type: AwardWarningLevel.INFO,
                    series: 1,
                    message: t`One TA Award (Connect, Reach, or Sustain) must be given`,
                    contextMessage: t`One TA Award (Connect, Reach, or Sustain) must be given`
                })
            })
        } else if (taAwardsWithWinners.length > 1) {
            taAwardsWithWinners.forEach(a => {
                awardWarnings[a.awardId].push({
                    type: AwardWarningLevel.ERROR,
                    series: 1,
                    message: t`Only one TA Award (Connect, Reach, or Sustain) may be given`,
                    contextMessage: t`Multiple TA awards given!`
                })
            })
        }
    }

    if(mciAwards.every(a => a.requiredCount == 0)) {
        const mciAwardsWithWinners = mciAwards.filter(a => awardAssignmentData.data[a.awardId].some(a => a.series == 1 && a.team));
        if(mciAwardsWithWinners.length == 0) {
            mciAwards.forEach(a => {
                awardWarnings[a.awardId].push({
                    type: AwardWarningLevel.INFO,
                    series: 1,
                    message: t`One MCI Award (Design, Innovate, or Control) must be given`,
                    contextMessage: t`One MCI Award (Design, Innovate, or Control) must be given`
                })
            })
        } else if(mciAwardsWithWinners.length > 1) {
            mciAwardsWithWinners.forEach(a => {
                awardWarnings[a.awardId].push({
                    type: AwardWarningLevel.ERROR,
                    series: 1,
                    message: t`Only one MCI Award (Design, Innovate, or Control) may be given`,
                    contextMessage: t`Multiple MCI awards given!`
                })
            })
        }
    }

    return <div>
        <Row>
            <Col sm={10}>
                <h2>{t`Enter Awards`}</h2>
            </Col>
            {window.FIRST_ENV.projectName == 'FTCCloud' ? null : <Col sm={2}>
                {/* TODO unsubmit */}
                <Button variant={awardPresentationContext.data?.areTeamAwardsSubmitted ? "warning" : (Object.values(awardWarnings).some(a => a.length > 0) ? "danger" : "primary")} className={"float-end"} onClick={() => awardPresentationContext.data?.areTeamAwardsSubmitted ? unsubmitAwardsMutation.mutate() : submitAwardsMutation.mutate({ awards: editableAwards, awardWarnings })}>
                    {awardPresentationContext.data?.areTeamAwardsSubmitted ? t`Unsubmit Awards` : t`Submit Awards`}
                </Button>
            </Col>}
        </Row>
        <Row>
            <Col lg={4}>
                <ListGroup>
                    {editableAwards.map(((a) => {
                        const warnings = awardWarnings[a.awardId] ?? [];
                        const winner = awardAssignmentData.data[a.awardId]?.find(aa => aa.series == 1)
                        const hasWinner = a.isTeamAward && winner?.team || winner?.name
                        return <ListGroup.Item key={a.awardId} action eventKey={a.awardId} onClick={() => setSelectedAward(a.awardId)}
                                               variant={hasWinner ? (warnings.some(w => w.type == AwardWarningLevel.ERROR) ? "danger" : (warnings.some(w => w.type == AwardWarningLevel.WARNING) ? "warning" : "success")) : (warnings.some(w => w.type == AwardWarningLevel.INFO) ? "primary" : "secondary")}
                                               active={selectedAward == a.awardId}>
                            <span dangerouslySetInnerHTML={{__html: a.name}} /> {warnings?.length > 0 ? <OverlayTrigger
                                    placement="right"
                                    overlay={
                                        <Tooltip id={`${a.awardId}-warning-tooltip`}>
                                            <div className={"text-left"}>
                                                {warnings.map((w, idx) => <p key={idx} className={idx == warnings.length - 1 ? "mb-0" : ""}>{w.message}</p>)}
                                            </div>
                                        </Tooltip>
                                    }
                                >
                                    <i className={"fa fa-exclamation-triangle float-right text-body"}/>
                                </OverlayTrigger> : null}<br/>
                            {a.awardTypeId != AwardId.DEANSLIST_ID ? (hasWinner ? (a.isTeamAward ? `${winner.team?.displayNumber} ${winner.team?.name}` : (winner.team ? `${winner.name} - ${winner.team.displayNumber} ${winner.team.name}` : winner.name)) : t`NOT GIVEN`) : null}<br/>
                        </ListGroup.Item>
                    }))}
                </ListGroup>
            </Col>
            <Col lg={8}>
                {selectedAward ? <AwardAssignmentsEditor award={awardData.data.find(a => a.awardId == selectedAward)!} awardAssignments={awardAssignmentData.data[selectedAward]} warnings={awardWarnings[selectedAward] ?? []}/> : <div>{t`Select an award to edit`}</div>}
            </Col>
        </Row>
    </div>
}