import {createAward, deleteAward, listAwards, saveAward, swapAwards} from "../api";
import {useMutation, useQuery, useQueryClient} from "@tanstack/react-query";
import {Button, Card, Form} from "react-bootstrap";
import {t} from "../../i18n";
import {useEffect, useState} from "react";
import {Award, AwardId} from "../../javaTypes";
import {confirmDialog} from "first-common/dialogs";

function AwardEditor({award, moveUp, moveDown, close}: {
    award?: Award, moveUp?: () => void, moveDown?: () => void, close?: () => void
}) {
    const [isEditing, setIsEditing] = useState(!award);
    const [isTeamAward, setIsTeamAward] = useState(award?.isTeamAward || false);
    const [name, setName] = useState(award?.name || '');
    const [script, setScript] = useState(award?.script || '');
    const queryClient = useQueryClient();

    // On toggle of editing, reset back to the value in the underlying object
    useEffect(() => {
        const parsedName = new DOMParser().parseFromString(award?.name || '', "text/html");
        const parsedScript = new DOMParser().parseFromString(award?.script || '', "text/html");
        setIsTeamAward(award?.isTeamAward || false)
        setName(parsedName.documentElement.textContent || '')
        setScript(parsedScript.documentElement.textContent || '')
    }, [award, isEditing]);

    const createAwardMutation = useMutation({
        mutationFn: async ({isTeamAward, name, script}: {isTeamAward: boolean, name: string, script: string}) => {
            await createAward(window.eventCode, isTeamAward, name, script)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({ queryKey: ["awards", window.eventCode] });
        }
    })

    const saveAwardMutation = useMutation({
        mutationFn: async ({awardId, isTeamAward, name, script}: {awardId: string, isTeamAward: boolean, name: string, script: string}) => {
            await saveAward(window.eventCode, awardId, isTeamAward, name, script)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({ queryKey: ["awards", window.eventCode] });
        }
    })

    const deleteAwardMutation = useMutation({
        mutationFn: async ({awardId}: {awardId: string}) => {
            await deleteAward(window.eventCode, awardId);
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({ queryKey: ["awards", window.eventCode] });
        }
    })

    return <Card className={"mb-2"}>
        <Card.Header className={"d-flex align-items-center justify-content-between"}>
            {isEditing ? <Form.Control style={{width: 'auto'}} value={name} onChange={e => setName(e.target.value)} /> : <span dangerouslySetInnerHTML={{__html: name}}></span>}
            <div className={"d-flex align-items-center"}>
                <Form.Check type="checkbox" checked={isTeamAward} id={`award-${award?.awardId || 'creatingNew'}-isTeamAward`}
                            label={t`Team Award?`} className={"mr-3"} disabled={!isEditing} onChange={(e) => setIsTeamAward(e.target.checked)} />
                {award?.editable || !award ? (isEditing ? <>
                        <Button variant={"secondary"} onClick={() => {
                            if(award) {
                                setIsEditing(false)
                            } else if(close) {
                                close()
                            }
                        }}>{t`Cancel`}</Button>
                        <Button className={"ml-2"} onClick={async () => {
                            if(award) {
                                saveAwardMutation.mutate({ awardId: award.awardId, isTeamAward, name, script }, {
                                    onSuccess: () => {
                                        setIsEditing(false)
                                    }
                                })
                            } else {
                                createAwardMutation.mutate({ isTeamAward, name, script }, {
                                    onSuccess: () => {
                                        if(close) {
                                            close()
                                        }
                                    }
                                })
                            }
                        }}>{t`Save`}</Button>
                    </> : <>
                        <Button onClick={() => setIsEditing(true)}>{t`Edit`}</Button>
                        {/* Prevent deleting built-in awards */}
                        {award?.awardTypeId == AwardId.CUSTOM_ID ? <Button variant={"danger"} className={"ml-2"}
                            onClick={async (e) => {
                                if(!await confirmDialog({
                                    label: t`Delete Award?`,
                                    text: t`Are you sure you want to delete the "${award.name}" award? This cannot be undone.`,
                                    buttonText: t`Delete`,
                                })) {
                                    return
                                }
                                deleteAwardMutation.mutate({ awardId: award.awardId });
                            }}>{t`Delete`}</Button> : null}
                    </>): null}
                {moveUp || moveDown ? <>
                    <Button variant={"secondary"} disabled={!moveUp} className={"ml-2"} onClick={async () => {
                        if(!moveUp) {
                            return
                        }
                        moveUp()
                    }}><i className={"fa fa-arrow-up"}></i></Button>
                    <Button variant={"secondary"} disabled={!moveDown} className={"ml-1"} onClick={async () => {
                        if(!moveDown) {
                            return
                        }
                        moveDown()
                    }}><i className={"fa fa-arrow-down"}></i></Button>
                </> : null}
            </div>
        </Card.Header>
        <Card.Body>
            <Form.Control as="textarea" rows={4} value={script} onChange={(e) => setScript(e.target.value)} readOnly={!isEditing}/>
        </Card.Body>
    </Card>;
}

export default function ManageAwards() {
    const awardData = useQuery({
        queryKey: ["awards", window.eventCode],
        queryFn: () => listAwards(window.eventCode)
    })
    const [creatingNew, setCreatingNew] = useState(false);

    const queryClient = useQueryClient();
    const swapAwardsMigration = useMutation({
        mutationFn: async ({id1, id2}: {id1: string, id2: string}) => {
            await swapAwards(window.eventCode, id1, id2)
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({ queryKey: ["awards", window.eventCode] });
        }
    })

    if(awardData.isLoading || awardData.isPending ) {
        return <div>{t`Loading...`}</div>
    }
    if(awardData.isError) {
        return <div>{t`Error`}</div>
    }

    const sortedAwards = [...awardData.data].sort((a, b) => a.order - b.order)

    return <div>
        <h2>{t`Manage Awards`}</h2>
        {t`Presented in order listed. Only custom awards can be reordered.`}<br/>
        {creatingNew ? <AwardEditor close={() => setCreatingNew(false)} /> : <Button className={"mb-3"} onClick={() => setCreatingNew(true)}>{t`Create New Award`}</Button>}
        {sortedAwards.map((award, idx) => <AwardEditor key={award.awardId} award={award}
            moveUp={idx > 0 && award.awardTypeId == AwardId.CUSTOM_ID ? () => swapAwardsMigration.mutate({ id1: sortedAwards[idx - 1].awardId, id2: award.awardId }) : undefined}
            moveDown={idx < sortedAwards.length - 1 && award.awardTypeId == AwardId.CUSTOM_ID && sortedAwards[idx + 1].awardTypeId == AwardId.CUSTOM_ID ?
                () => swapAwardsMigration.mutate({ id1: award.awardId, id2: sortedAwards[idx + 1].awardId }) : undefined}
        />)}
    </div>
}