import {createRoot} from "react-dom/client";
import {QueryClient, QueryClientProvider, useIsMutating} from "@tanstack/react-query";
import GiveAwards from "./GiveAwards";
import {ViewClosingScript, ViewOpeningScript} from "../ViewScript";
import {FTCConstants, ProgramConstants} from "../../javaTypes";
import PresentAwards from "./PresentAwards";
import ManageAwardsHeader from "./ManageAwardsHeader";
import ManageAwards from "./ManageAwards";
import SyncAwards from "./SyncAwards";
import {Alert} from "react-bootstrap";
import {ComponentType, useEffect, useState} from "react";
import {t} from "../../i18n";

declare global {
    interface Window {
        eventCode: string;
        eventName: string;
        eventArchived: boolean;
        canPresent: boolean;
        ftcConstants: ProgramConstants;
    }
}

// Should never be hit, but more useful than a null fallback
function NotFoundPage() {
    return <div>
        404 Not Found
    </div>
}

function EditPendingIndicator() {
    const isMutating = useIsMutating()
    const [showSavingIndicator, setShowSavingIndicator] = useState(isMutating > 0)

    useEffect(() => {
        if(isMutating > 0) {
            setShowSavingIndicator(true)
        } else {
            // Delay hiding "saving" for better user experience
            const timeout = setTimeout(() => setShowSavingIndicator(false), 500);
            return () => clearTimeout(timeout);
        }
    }, [isMutating]);

    return <div style={{
        position: 'fixed',
        bottom: 0,
        right: 0,
        width: '12em',
        zIndex: 1000,
        padding: '10px',
        textAlign: 'center'
    }}>
        <Alert variant={showSavingIndicator ? 'info' : 'success'}>
            {showSavingIndicator ? <><i className="fa fa-spinner fa-spin" /> {t`Saving...`}</> : <><i className="fa fa-check" /> {t`All edits saved`}</>}
        </Alert>
    </div>
}

const container = document.getElementById('reactContainer');
const queryClient = new QueryClient();
if(!container) {
    console.error("Mount point for runtime container not found")
} else {
    const root = createRoot(container);

    let Component: ComponentType = NotFoundPage;
    // Filter out local trailing slashes
    const page = document.location.pathname.split('/').filter(x => x.length > 0).pop();
    if(page === 'give_awards') {
        Component = GiveAwards;
    } else if(page === 'view_opening_script') {
        Component = ViewOpeningScript;
    } else if(page === 'view_script') {
        Component = ViewClosingScript;
    } else if(page === 'present_awards') {
        Component = PresentAwards;
    } else if(page === 'manage_awards') {
        Component = ManageAwards;
    } else if(page === 'data_transfer') {
        Component = SyncAwards;
    } else {
        throw new Error(`Unknown page: ${page}`);
    }
    root.render(<QueryClientProvider client={queryClient}>
        <ManageAwardsHeader />
        <Component />
        { page == 'give_awards' || page == 'manage_awards' ? <EditPendingIndicator /> : null }
    </QueryClientProvider>);
}