import {t} from "../../i18n";
import {giveAwardsUrl} from "./ManageAwardsHeader";
import {jt} from "ttag";
import {Button, Form} from "react-bootstrap";
import {ChangeEvent, useState} from "react";
import { confirmDialog, messageDialog } from "first-common/dialogs";
import {useAwardPresentationContext} from "../api";

async function handleError(status: number, message?: string) {
    if (status === 409) {
        return await confirmDialog({
            label: t`Awards Import Warning`,
            text: message || '',
            buttonText: t`Continue`,
        })
    } else if (status === 404) {
        messageDialog({
            label: t`Awards Import Error`,
            text: message + t` Cannot import this award data.`
        })
    } else if(status == 400) {
        messageDialog({
            label: t`Awards Import Error`,
            text: t`The file imported is not in a supported format.<br/><br/>For immediate resolution, please enter the awards directly using the <a href='../give_awards/'>Give Awards</a> tab. For support, please contact the developers of the software which generated the file.`,
            dangerous: true
        })
    } else {
        messageDialog({
            label: t`Awards Import Error`,
            text: t`An error occurred during award import.<br/><br/>For immediate resolution, please enter the awards directly using the <a href='../give_awards/'>Give Awards</a> tab. Please notify support of this issue through the support chat or file an issue on GitHub.`,
            dangerous: true
        })
    }
    return false;
}

export default function SyncAwards() {
    const enterAwardsLink = <a key="enterAwards" href={giveAwardsUrl}>{t`Enter Awards tab`}</a>
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const presentationContext = useAwardPresentationContext(window.eventCode);
    const eventKeyValid = presentationContext?.data?.isSyncConfigured;

    async function sync() {
        const initialRequest = await fetch("../sync/", {
            method: "POST",
        })
        if(initialRequest.ok) {
            window.location.href = "../give_awards/";
            return
        }
        if(await handleError(initialRequest.status, await initialRequest.text())) {
            const secondRequest = await fetch("../sync/?confirmed=true", {
                method: "POST",
            })
            if(secondRequest.ok) {
                window.location.href = "../give_awards/";
            } else {
                await handleError(secondRequest.status, await secondRequest.text());
            }
        }
    }

    async function importAwards() {
        if(!selectedFile) {
            return;
        }
        const formData = new FormData();
        formData.append("uploaded_file", selectedFile);
        const initialRequest = await fetch("../import/", {
            method: "POST",
            body: formData,
        })
        if(initialRequest.ok) {
            window.location.href = "../give_awards/";
            return
        }
        if(await handleError(initialRequest.status, await initialRequest.text())) {
            const secondRequest = await fetch("../import/?confirmed=true", {
                method: "POST",
                body: formData,
            })
            if(secondRequest.ok) {
                window.location.href = "../give_awards/";
            } else {
                await handleError(secondRequest.status, await secondRequest.text());
            }
        }
    }

    return <div>
        <h2>{t`Import/Export Awards`}</h2>
        <br/>
        <h6 className="text-center">{jt`After a successful sync/import, be sure to validate the data on the ${enterAwardsLink}.`}</h6>
        <div className={"d-flex flex-column align-items-center"}>
            <div className={"w-100"}>
                <hr/>
            </div>
            <Button variant={"secondary"} onClick={sync} disabled={!eventKeyValid} title={t`No valid Event Key`}>{t`Sync From Online Scoring System`}</Button>
            <div className={"w-100"}>
                <hr/>
            </div>
            <Button variant={"secondary"} href="../export/">{t`Export Awards`}</Button>
            <div className={"w-100"}>
                <hr/>
            </div>
            <div className={"d-flex align-items-center"}>
                <Form.File style={{width: '400px'}} custom label={selectedFile?.name || 'Select a file'} onChange={(e: ChangeEvent<HTMLInputElement>) => setSelectedFile(e.target.files ? e.target.files[0] : null)} />
                <Button variant={"secondary"} className="ml-2" onClick={importAwards} disabled={!selectedFile}>{t`Import Awards`}</Button>
            </div>
        </div>
    </div>
}