import {t} from "../../i18n";
import {normalizeUrl} from "../../utils";
import {Button, Nav} from "react-bootstrap";
import {jt} from "ttag";

const isCloud = window.FIRST_ENV.projectName == 'FTCCloud'
export const giveAwardsUrl = normalizeUrl(`/event/${window.eventCode}${isCloud ? '' : '/dashboard'}/awards/give_awards`)
const manageAwardsUrl = normalizeUrl(`/event/${window.eventCode}/dashboard/awards/manage_awards/`)
const viewOpeningScriptUrl = normalizeUrl(`/event/${window.eventCode}${isCloud ? '' : '/dashboard'}/awards/view_opening_script`)
const viewScriptUrl = normalizeUrl(`/event/${window.eventCode}${isCloud ? '' : '/dashboard'}/awards/view_script`)
const presentAwardsUrl = normalizeUrl(`/event/${window.eventCode}${isCloud ? '' : '/dashboard'}/awards/present_awards`)
const dataTransferUrl = normalizeUrl(`/event/${window.eventCode}/dashboard/awards/data_transfer`)

export default function ManageAwardsHeader() {
    const firstTag = <i>FIRST</i>

    return <div className="text-center d-print-none">
        {window.eventArchived ?
            <div className="col-md-6 offset-md-3">
                <div className="form-group">
                    {jt`This event has been archived and uploaded to ${firstTag}.`}<br/>
                    {jt`If you need to make any changes, please contact ${firstTag} event help.`}
                    <hr />
                </div>
            </div> : null}
        <h1>{t`Awards Manager`}</h1>
        <h5 className="col-12">[{window.eventCode}] {window.eventName}</h5>

        <br/>
        <Nav variant="pills" className={"mb-4"}>
            <Nav.Item>
                <Button className={"mr-2"} variant={"dark"} href={`/event/${window.eventCode}/`}>{t`Exit`}</Button>
            </Nav.Item>
            {isCloud ?  <>
                <Nav.Item>
                    <Nav.Link href={`/sync/awards/${window.eventCode}`}>{t`Export Awards`}</Nav.Link>
                </Nav.Item>
                <Nav.Item>
                    <Nav.Link href={`/event/${window.eventCode}/awards/eligibility`}>{t`Eligibility`}</Nav.Link>
                </Nav.Item>
            </> : <>
                <Nav.Item>
                    <Nav.Link active={window.location.pathname == manageAwardsUrl} href={manageAwardsUrl}>{t`Manage Awards`}</Nav.Link>
                </Nav.Item>
                <Nav.Item>
                    <Nav.Link active={window.location.pathname == dataTransferUrl} href={dataTransferUrl}>{t`Import/Export`}</Nav.Link>
                </Nav.Item>
            </>}
            <Nav.Item>
                <Nav.Link active={window.location.pathname == giveAwardsUrl} href={giveAwardsUrl}>{t`Enter Awards`}</Nav.Link>
            </Nav.Item>
            <Nav.Item>
                <Nav.Link active={window.location.pathname == viewOpeningScriptUrl} href={viewOpeningScriptUrl}>{t`Opening Script`}</Nav.Link>
            </Nav.Item>
            <Nav.Item>
                <Nav.Link active={window.location.pathname == viewScriptUrl} href={viewScriptUrl}>{t`Playoff Awards Script`}</Nav.Link>
            </Nav.Item>
            {window.canPresent ? <>
                <Nav.Item>
                    <Nav.Link active={window.location.pathname == presentAwardsUrl} href={presentAwardsUrl}>{t`Present Awards/Advancement`}</Nav.Link>
                </Nav.Item>
            </> : null}
        </Nav>
    </div>
}